const body = $input.first().json.body ?? $input.first().json;

// Normalize field names from GMI payload variants
const supplier_name =
  body.supplier_name ??
  body.creditor_name ??
  body.vendor ??
  body.supplier ??
  'Unknown';

const amount =
  body.total_amount ??
  body.amount ??
  body.gross_amount ??
  null;

const currency =
  body.currency ??
  body.currency_code ??
  'EUR';

const invoice_date =
  body.invoice_date ??
  body.date ??
  null;

const due_date =
  body.due_date ??
  body.payment_due_date ??
  null;

const invoice_number =
  body.invoice_number ??
  body.document_number ??
  body.number ??
  null;

// Guess category from supplier name
const s = (supplier_name ?? '').toLowerCase();
let category = 'other';
if (/saas|software|cloud|notion|slack|github|figma|linear|vercel|netlify|stripe|klaviyo|hubspot/.test(s)) {
  category = 'software';
} else if (/dhl|ups|fedex|dpd|hermes|gls|logistik|shipping|spedition|freight|transport/.test(s)) {
  category = 'logistics';
} else if (/meta|google|tiktok|ads|media|marketing|agency|agentur|influencer|creative|facebook/.test(s)) {
  category = 'marketing';
}

return [
  {
    json: {
      supplier_name,
      amount,
      currency,
      invoice_date,
      due_date,
      invoice_number,
      category,
      raw_payload: body
    }
  }
];

